  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb$Mejores tipos de tropa$hb$, $hb$Mages totalmente aquí para lidiar con la Infantry, ya que necesitas daño mágico con él$hb$, '{}'::text[], $hb$https://www.allclash.com/best-cantaman-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb$Mejores parejas de héroe para Cantaman$hb$, $hb$Vardun está diseñado para trabajar tan bien con sus debuffs y saltarse tanta defensa que cualquier marcha de Infantry está en problemas, y debería ser tu opción principal (Mira la build completa aquí).
