  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb$Mejores sinergias de mascota para Cantaman (NUEVO)$hb$, $hb$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Cantaman con la mascota correcta para obtener más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb$, '{}'::text[], $hb$https://www.allclash.com/best-cantaman-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb$Mejores builds para Cantaman$hb$, $hb$A continuación encontrarás las builds de árbol de talentos para Cantaman que tienen sentido cuando lo usas como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, ya que explico una ruta general sobre cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente apreciarás. A menos que seas uno de los pocos jugadores que realmente hace Rally con él, en campo abierto lo usarías normalmente como comandante secundario con Vardun, así que el árbol de talentos no es importante; pero si los separas en dos marchas y él liderara la otra, el árbol de habilidades es siempre tu elección como se muestra aquí$hb$, array[$hb$https://www.allclash.com/wp-content/uploads/2026/05/cantaman-talent-tree.jpg$hb$]::text[], $hb$https://www.allclash.com/best-cantaman-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
