  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb$Mejores parejas de héroe para Seluna Legendary$hb$, $hb$Atheus es una pareja absolutamente excelente con ella, ya que ambos escalan a partir de sus ataques básicos y él proporciona la rage para su burst para seguir generando bola de nieve, y juntos tienen bastante buena velocidad de marcha (Mira la build completa aquí).
