  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb$Mejores parejas de héroe para Freya$hb$, $hb$Agnar es obviamente la mejor elección aquí y está diseñado para ser tremendamente fuerte junto a Freya. Literalmente acaban con todo al inicio de la G5 a menos que se lancen counters más adelante (Mira la build completa aquí).
