  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb$Mejores parejas de héroe para Kaelan$hb$, $hb$Ruby es la mejor comandante principal para usar con él, simplemente porque Kaelan potencia su kit y su kit activa las habilidades de él demasiado bien como para hacer que cualquier otra pareja sea ni remotamente tan fuerte (Mira la build completa aquí).
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb$Mejores artefactos$hb$, $hb$Esto depende de con qué héroe lo emparejes, ¡Kaelan no es un héroe para usar como comandante principal!$hb$, '{}'::text[], $hb$https://www.allclash.com/best-kaelan-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
